import{_ as i,C as n,o as s,c as l,E as r,w as o,a,a0 as d}from"./chunks/framework.CkNTPv-z.js";const v=JSON.parse('{"title":"Moving to Portugal","description":"Immigration pathways and relocation guide for transgender people moving to Portugal","frontmatter":{"layout":"doc","title":"Moving to Portugal","description":"Immigration pathways and relocation guide for transgender people moving to Portugal"},"headers":[],"relativePath":"europe/portugal/moving-there.md","filePath":"europe/portugal/moving-there.md","lastUpdated":null}'),g={name:"europe/portugal/moving-there.md"};function u(c,e,h,p,m,f){const t=n("Badge");return s(),l("div",null,[r(t,{variant:"green"},{default:o(()=>[...e[0]||(e[0]=[a("Multiple Visa Options",-1)])]),_:1}),r(t,{variant:"green"},{default:o(()=>[...e[1]||(e[1]=[a("Moderate Cost of Living",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="moving-to-portugal" tabindex="-1">Moving to Portugal <a class="header-anchor" href="#moving-to-portugal" aria-label="Permalink to &quot;Moving to Portugal&quot;">​</a></h1><h2 id="immigration-pathways" tabindex="-1">Immigration Pathways <a class="header-anchor" href="#immigration-pathways" aria-label="Permalink to &quot;Immigration Pathways&quot;">​</a></h2><h3 id="eu-eea-swiss-citizens" tabindex="-1">EU/EEA/Swiss Citizens <a class="header-anchor" href="#eu-eea-swiss-citizens" aria-label="Permalink to &quot;EU/EEA/Swiss Citizens&quot;">​</a></h3><p>Portugal grants full free movement rights to EU/EEA/Swiss citizens. Registration with the local town hall (Câmara Municipal) is required for stays over three months.</p><h3 id="non-eu-citizens" tabindex="-1">Non-EU Citizens <a class="header-anchor" href="#non-eu-citizens" aria-label="Permalink to &quot;Non-EU Citizens&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Visa Type</th><th>Description</th><th>Requirements</th><th>Duration</th></tr></thead><tbody><tr><td>D7 Passive Income Visa</td><td>For retirees and remote workers with passive income</td><td>Passive income ≥ €8,000/year (€760/month), accommodation proof</td><td>1 year, renewable, leads to residency</td></tr><tr><td>D8 Digital Nomad Visa</td><td>For remote workers</td><td>Remote work proof, income ≥ €3,280/month</td><td>1 year, renewable</td></tr><tr><td>D2 Entrepreneurs Visa</td><td>For business owners and freelancers</td><td>Business plan or freelance proof, minimum income</td><td>1 year, renewable</td></tr><tr><td>Work Visa (D1)</td><td>For employment with Portuguese employer</td><td>Job offer from Portuguese company</td><td>1 year, renewable</td></tr><tr><td>Golden Visa</td><td>For real estate investors</td><td>Property purchase ≥ €280,000-€500,000 (depending on area)</td><td>2 years, renewable, leads to citizenship</td></tr><tr><td>Family Reunification</td><td>For family of residents</td><td>Relationship proof, sufficient income</td><td>1 year, renewable</td></tr><tr><td>Student Visa</td><td>For full-time study</td><td>University acceptance, funds proof</td><td>1 year, renewable</td></tr></tbody></table><h2 id="key-relocation-steps" tabindex="-1">Key Relocation Steps <a class="header-anchor" href="#key-relocation-steps" aria-label="Permalink to &quot;Key Relocation Steps&quot;">​</a></h2><ol><li><strong>Choose your visa pathway</strong> — D7 is most popular for remote workers/retirees</li><li><strong>Apply for a visa</strong> — At the Portuguese consulate in your country of residence</li><li><strong>Secure accommodation</strong> — Proof required for visa application</li><li><strong>Register with the town hall</strong> — After arrival</li><li><strong>Apply for a residence permit</strong> — At SEF (Serviço de Estrangeiros e Fronteiras)</li><li><strong>Get a NIF (tax number)</strong> — Required for everything: bank account, utilities, phone</li><li><strong>Open a bank account</strong> — Required for NIF and residency</li><li><strong>Register with SNS (healthcare)</strong> — For public health access</li><li><strong>Learn Portuguese</strong> — A2 level required for citizenship</li></ol><h2 id="cost-of-living" tabindex="-1">Cost of Living <a class="header-anchor" href="#cost-of-living" aria-label="Permalink to &quot;Cost of Living&quot;">​</a></h2><p>Portugal offers a moderate cost of living compared to other Western European countries:</p><ul><li>Rent (1-bedroom): €600-1,200/month (Lisbon); €400-800 (Porto); €300-600 (interior)</li><li>Groceries: €200-350/month</li><li>Public transport: €30-60/month pass</li><li>Health insurance: Private insurance €30-80/month</li><li>Eating out: €10-20 for a meal</li></ul><h2 id="trans-specific-relocation-tips" tabindex="-1">Trans-Specific Relocation Tips <a class="header-anchor" href="#trans-specific-relocation-tips" aria-label="Permalink to &quot;Trans-Specific Relocation Tips&quot;">​</a></h2><ul><li><strong>Portugal is very safe</strong> — consistently ranks as one of the safest countries globally</li><li><strong>English is spoken in major cities</strong> and tourist areas, but less so in rural areas</li><li><strong>Healthcare for HRT is best in Lisbon and Porto</strong></li><li><strong>Bring medical records translated into Portuguese</strong></li><li><strong>Carry at least 3 months of HRT medication</strong> with a doctor&#39;s letter</li><li><strong>Register with a GP (médico de família)</strong> at your local health centre (centro de saúde)</li><li><strong>The D7 visa is the most popular path</strong> for remote workers — no job offer needed</li><li><strong>Consider Porto over Lisbon</strong> — lower cost of living, good trans healthcare, less crowded</li><li><strong>ILGA Portugal</strong> provides community support and trans-specific resources</li><li><strong>Lisbon and Porto have active LGBTQ+ scenes</strong>; smaller towns may have less visibility</li></ul><h2 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h2><ul><li><strong>Official language</strong>: Portuguese</li><li><strong>English</strong> — Widely spoken in Lisbon, Porto, Algarve, and by younger generations</li><li><strong>Portuguese</strong> A2 level required for citizenship</li><li>Free Portuguese language courses available through the government (PLA programme)</li></ul><h2 id="citizenship-timeline" tabindex="-1">Citizenship Timeline <a class="header-anchor" href="#citizenship-timeline" aria-label="Permalink to &quot;Citizenship Timeline&quot;">​</a></h2><p>After 5 years of legal residence, you can apply for Portuguese citizenship. Portugal has one of the most favourable citizenship-by-naturalisation policies in Europe.</p><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><strong>SEF (Immigration Service)</strong> — <a href="https://www.sef.pt/" target="_blank" rel="noreferrer">sef.pt</a></li><li><strong>Portal do Cidadão</strong> — Citizen portal: <a href="https://www.portaldocidadao.pt/" target="_blank" rel="noreferrer">portaldocidadao.pt</a></li><li><strong>Autoridade Tributária (Tax Authority)</strong> — NIF registration: <a href="https://www.portaldasfinancas.gov.pt/" target="_blank" rel="noreferrer">portaldasfinancas.gov.pt</a></li><li><strong>SNS (Public Health)</strong> — <a href="https://www.sns.gov.pt/" target="_blank" rel="noreferrer">sns.gov.pt</a></li><li><strong>ILGA Portugal</strong> — <a href="https://www.ilga-portugal.pt/" target="_blank" rel="noreferrer">ilga-portugal.pt</a></li><li><strong>Expats Portugal</strong> — Community forum: <a href="https://www.expatsportugal.com/" target="_blank" rel="noreferrer">expatsportugal.com</a></li></ul>',19))])}const w=i(g,[["render",u]]);export{v as __pageData,w as default};
